/**
 * Format a number as USD currency.
 * formatCurrency(1234.5) => "$1,234.50"
 */
export function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount);
}

/**
 * Truncate a string to maxLength and add ellipsis.
 * truncate("Hello World", 5) => "Hello..."
 */
export function truncate(str: string, maxLength: number): string {
  if (str.length <= maxLength) return str;
  return str.slice(0, maxLength) + '...';
}

/**
 * Calculate a percentage, clamped between 0 and 100.
 * percentage(3, 10) => 30
 */
export function percentage(part: number, total: number): number {
  if (total === 0) return 0;
  return Math.min(100, Math.max(0, Math.round((part / total) * 100)));
}

/**
 * Parse a query string into an object.
 * parseQuery("?page=2&sort=name") => { page: "2", sort: "name" }
 */
export function parseQuery(queryString: string): Record<string, string> {
  const params = new URLSearchParams(queryString);
  const result: Record<string, string> = {};
  params.forEach((value, key) => { result[key] = value; });
  return result;
}

import { formatCurrency, truncate, percentage, parseQuery } from '../formatters';

describe('formatCurrency', () => {
  it('formats a whole number with cents', () => {
    expect(formatCurrency(1234)).toBe('$1,234.00');
  });

  it('formats a decimal number', () => {
    expect(formatCurrency(99.9)).toBe('$99.90');
  });

  it('handles zero', () => {
    expect(formatCurrency(0)).toBe('$0.00');
  });

  it('handles negative numbers', () => {
    expect(formatCurrency(-50)).toBe('-$50.00');
  });
});

describe('truncate', () => {
  it('returns the full string if shorter than maxLength', () => {
    expect(truncate('Hi', 10)).toBe('Hi');
  });

  it('truncates and adds ellipsis', () => {
    expect(truncate('Hello World', 5)).toBe('Hello...');
  });

  it('returns exact length string without truncating', () => {
    expect(truncate('Hello', 5)).toBe('Hello');
  });
});

describe('percentage', () => {
  it('calculates a basic percentage', () => {
    expect(percentage(3, 10)).toBe(30);
  });

  it('returns 0 when total is 0', () => {
    expect(percentage(5, 0)).toBe(0);
  });

  it('clamps to 100 when part exceeds total', () => {
    expect(percentage(15, 10)).toBe(100);
  });

  it('rounds to nearest integer', () => {
    expect(percentage(1, 3)).toBe(33);
  });
});

describe('parseQuery', () => {
  it('parses a query string into an object', () => {
    expect(parseQuery('?page=2&sort=name')).toEqual({ page: '2', sort: 'name' });
  });

  it('handles an empty query string', () => {
    expect(parseQuery('')).toEqual({});
  });

  it('handles a query without the leading question mark', () => {
    expect(parseQuery('key=value')).toEqual({ key: 'value' });
  });
});

import { renderHook, act } from '@testing-library/react';
import { useDebounce } from '../useDebounce';

// Tell Jest to use fake timers so we can control time
beforeEach(() => jest.useFakeTimers());
afterEach(() => jest.useRealTimers());

describe('useDebounce', () => {
  it('returns the initial value immediately', () => {
    const { result } = renderHook(() => useDebounce('hello', 500));
    expect(result.current).toBe('hello');
  });

  it('does not update the value before the delay', () => {
    const { result, rerender } = renderHook(
      ({ value, delay }) => useDebounce(value, delay),
      { initialProps: { value: 'hello', delay: 500 } }
    );

    // Change the value
    rerender({ value: 'world', delay: 500 });

    // Advance time by 300ms (less than the 500ms delay)
    act(() => jest.advanceTimersByTime(300));

    // Should still be the old value
    expect(result.current).toBe('hello');
  });

  it('updates the value after the delay', () => {
    const { result, rerender } = renderHook(
      ({ value, delay }) => useDebounce(value, delay),
      { initialProps: { value: 'hello', delay: 500 } }
    );

    rerender({ value: 'world', delay: 500 });

    // Advance time by the full delay
    act(() => jest.advanceTimersByTime(500));

    expect(result.current).toBe('world');
  });
});

import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import SearchBar from '../SearchBar';

describe('SearchBar', () => {
  it('renders an input with placeholder text', () => {
    render(<SearchBar onSearch={jest.fn()} />);
    expect(screen.getByPlaceholderText('Search...')).toBeInTheDocument();
  });

  it('calls onSearch when the form is submitted', async () => {
    const mockOnSearch = jest.fn();
    const user = userEvent.setup();

    render(<SearchBar onSearch={mockOnSearch} />);

    const input = screen.getByPlaceholderText('Search...');
    await user.type(input, 'react testing');
    await user.keyboard('{Enter}');

    expect(mockOnSearch).toHaveBeenCalledWith('react testing');
  });

  it('clears the input when the clear button is clicked', async () => {
    const user = userEvent.setup();
    render(<SearchBar onSearch={jest.fn()} />);

    const input = screen.getByPlaceholderText('Search...');
    await user.type(input, 'hello');

    const clearButton = screen.getByRole('button', { name: /clear/i });
    await user.click(clearButton);

    expect(input).toHaveValue('');
  });

  it('disables the submit button when input is empty', () => {
    render(<SearchBar onSearch={jest.fn()} />);
    const submitButton = screen.getByRole('button', { name: /search/i });
    expect(submitButton).toBeDisabled();
  });
});

import { render, screen, waitFor } from '@testing-library/react';
import UserList from '../UserList';

// Mock the global fetch function
global.fetch = jest.fn();

const mockUsers = [
  { id: '1', name: 'Alice', email: 'alice@example.com' },
  { id: '2', name: 'Bob', email: 'bob@example.com' },
];

beforeEach(() => {
  (fetch as jest.Mock).mockReset();
});

describe('UserList', () => {
  it('shows a loading spinner while fetching', () => {
    // Return a promise that never resolves to keep loading state
    (fetch as jest.Mock).mockReturnValue(new Promise(() => {}));
    render(<UserList />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('renders users after successful fetch', async () => {
    (fetch as jest.Mock).mockResolvedValue({
      ok: true,
      json: async () => mockUsers,
    });

    render(<UserList />);

    // Wait for users to appear
    await waitFor(() => {
      expect(screen.getByText('Alice')).toBeInTheDocument();
      expect(screen.getByText('Bob')).toBeInTheDocument();
    });
  });

  it('shows an error message when fetch fails', async () => {
    (fetch as jest.Mock).mockRejectedValue(new Error('Network error'));

    render(<UserList />);

    await waitFor(() => {
      expect(screen.getByText(/failed to load users/i)).toBeInTheDocument();
    });
  });

  it('shows empty state when no users exist', async () => {
    (fetch as jest.Mock).mockResolvedValue({
      ok: true,
      json: async () => [],
    });

    render(<UserList />);

    await waitFor(() => {
      expect(screen.getByText(/no users found/i)).toBeInTheDocument();
    });
  });
});

