import { test, expect } from '@playwright/test';

test.describe('Login flow', () => {
  test('user can log in with valid credentials', async ({ page }) => {
    await page.goto('/login');

    // Fill in the login form
    await page.getByLabel('Email').fill('alice@example.com');
    await page.getByLabel('Password').fill('securePassword123');
    await page.getByRole('button', { name: 'Sign In' }).click();

    // Should redirect to dashboard
    await expect(page).toHaveURL('/dashboard');
    await expect(page.getByText('Welcome, Alice')).toBeVisible();
  });

  test('shows error for invalid credentials', async ({ page }) => {
    await page.goto('/login');

    await page.getByLabel('Email').fill('wrong@example.com');
    await page.getByLabel('Password').fill('wrongpassword');
    await page.getByRole('button', { name: 'Sign In' }).click();

    // Should show error message, not redirect
    await expect(page.getByText('Invalid credentials')).toBeVisible();
    await expect(page).toHaveURL('/login');
  });

  test('redirects unauthenticated users to login', async ({ page }) => {
    // Try to access a protected page directly
    await page.goto('/dashboard');

    // Should redirect to login
    await expect(page).toHaveURL('/login');
  });
});

import { test, expect } from '@playwright/test';

test.describe('Search functionality', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
  });

  test('displays search results as user types', async ({ page }) => {
    const searchInput = page.getByPlaceholder('Search...');
    await searchInput.fill('React');

    // Wait for results to appear (debounced search)
    const results = page.getByTestId('search-results');
    await expect(results).toBeVisible();

    // Should have at least one result
    const items = results.getByRole('listitem');
    await expect(items).not.toHaveCount(0);
  });

  test('shows empty state for no results', async ({ page }) => {
    const searchInput = page.getByPlaceholder('Search...');
    await searchInput.fill('xyznonexistentterm');

    await expect(page.getByText('No results found')).toBeVisible();
  });

  test('navigates to result on click', async ({ page }) => {
    const searchInput = page.getByPlaceholder('Search...');
    await searchInput.fill('React');

    // Click the first result
    const firstResult = page.getByTestId('search-results').getByRole('listitem').first();
    await firstResult.click();

    // Should navigate away from the home page
    await expect(page).not.toHaveURL('/');
  });
});

