import { retryWithBackoff } from '../retry';

beforeEach(() => jest.useFakeTimers());
afterEach(() => jest.useRealTimers());

test('retries a failed operation with exponential backoff', async () => {
  const operation = jest.fn()
    .mockRejectedValueOnce(new Error('fail 1'))  // 1st call fails
    .mockRejectedValueOnce(new Error('fail 2'))  // 2nd call fails
    .mockResolvedValue('success');                 // 3rd call succeeds

  const promise = retryWithBackoff(operation, { maxRetries: 3, initialDelay: 1000 });

  // First retry after 1000ms
  await jest.advanceTimersByTimeAsync(1000);
  // Second retry after 2000ms (exponential backoff)
  await jest.advanceTimersByTimeAsync(2000);

  const result = await promise;
  expect(result).toBe('success');
  expect(operation).toHaveBeenCalledTimes(3);
});

